B.KB=new A.bV("q3","business_admin","\uacbd\uc601\ud559","SWOT \ubd84\uc11d\uc5d0\uc11c \uae30\uc5c5 \ub0b4\ubd80 \uc5ed\ub7c9\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub974\uba74?",B.Fj,0,"SWOT \ubd84\uc11d\uc740 \uae30\uc5c5\uc758 \uacbd\uc601\ud658\uacbd\uc744 \ub0b4\ubd80 \uc694\uc778\uacfc \uc678\ubd80 \uc694\uc778\uc73c\ub85c \ub098\ub204\uc5b4 \ubd84\uc11d\ud558\ub294 \ub300\ud45c\uc801\uc778 \uc804\ub7b5 \uc218\ub9bd \ub3c4\uad6c\uc774\ub2e4. \uc774 \uc911 \uac15\uc810(Strength)\uacfc \uc57d\uc810(Weakness)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud560 \uc218 \uc788\ub294 \ub0b4\ubd80 \uc5ed\ub7c9(\uc790\uae08\ub825, \uae30\uc220\ub825, \uc870\uc9c1\ubb38\ud654, \ube0c\ub79c\ub4dc \ub4f1)\uc744 \ud3c9\uac00\ud55c \uac83\uc774\uace0, \uae30\ud68c(Opportunity)\uc640 \uc704\ud611(Threat)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud558\uae30 \uc5b4\ub824\uc6b4 \uc678\ubd80 \ud658\uacbd(\uc2dc\uc7a5 \uc131\uc7a5\ub960, \uacbd\uc7c1 \uac15\ub3c4, \uaddc\uc81c, \uac70\uc2dc\uacbd\uc81c \ub4f1)\uc744 \ud3c9\uac00\ud55c \uac83\uc774\ub2e4. \ub530\ub77c\uc11c \ub0b4\ubd80 \uc5ed\ub7c9\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc740 \uac15\uc810\uacfc \uc57d\uc810\uc774\uba70, \uc774\ub97c \ubc14\ud0d5\uc73c\ub85c SO(\uac15\uc810-\uae30\ud68c) \uc804\ub7b5, WT(\uc57d\uc810-\uc704\ud611) \uc804\ub7b5\ucc98\ub7fc \ub0b4\ubd80-\uc678\ubd80 \uc694\uc778\uc744 \uad50\ucc28 \ubd84\uc11d\ud558\uc5ec \uc804\ub7b5\uc744 \ub3c4\ucd9c\ud558\ub294 \uac83\uc774 SWOT \ubd84\uc11d\uc758 \ud575\uc2ec\uc774\ub2e4.",B.Eg,B.Er,"2025")
B.Dt=s(["\uc0ac\uc5c5\uc790\ub294 \uacc4\uc57d\uccb4\uacb0 \uc2dc \uace0\uac1d\uc774 \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uba85\uc2dc\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc0ac\uc5c5\uc790\ub294 \uace0\uac1d\uc758 \uc694\uccad\uc774 \uc788\uc73c\uba74 \uc57d\uad00\uc758 \uc0ac\ubcf8\uc744 \uace0\uac1d\uc5d0\uac8c \uad50\ubd80\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc5ec\uac1d\uc6b4\uc1a1\uc5c5, \uc804\uae30\xb7\uac00\uc2a4 \ubc0f \uc218\ub3c4\uc0ac\uc5c5\uc758 \uacbd\uc6b0 \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub294 \uba74\uc81c\ub418\ub098 \uc911\uc694\ud55c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34\uae4c\uc9c0 \uba74\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uace0\uac1d\uc774 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85\ud558\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0, \ud574\ub2f9 \uc57d\uad00\uc744 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c \uc8fc\uc7a5\ud560 \uc218 \uc5c6\ub2e4","\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc124\uba85\uc758\ubb34\ub294 \uba74\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.EP=s(['"\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0"\uc5d0\ub294 \uc608\uc678\uc801\uc73c\ub85c \uc774 \uc124\uba85\uc758\ubb34\uac00 \uba74\uc81c\ub41c\ub2e4'],t.s)
